class Solution {
public:
    int totalNQueens(int n) {
        int result = 0;
        for (int first_col = 0; first_col < n; first_col++) {
            int cols[n] = {false};
            int ld[n] = {false};
            int rd[n] = {false};
            int cur_row = 0;
            bool place(int row, int first_col, int cols[], int ld[], int rd[], int cur_row);
            result += place(0, first_col, cols, ld, rd, cur_row);
        }
        return result;
    }

    int place(int row, int first_col, int cols[], int ld[], int rd[], int cur_row) {
        if (row == n) return 1;
        for (int col = 0; col < n; col++)
            if (col != first_col && !cols[col] && !ld[row-col+first_col] && !rd[row+col-first_col])
            {
                cols[col] = ld[row-col+first_col] = rd[row+col-first_col] = true;
                result = place(row+1, first_col, cols, ld, rd, cur_row);
                cols[col] = ld[row-col+first_col] = rd[row+col-first_col] = false;
            }
        return 0;
    }
}

